# @cctt_verify {"v":2,"sym":"sympy.physics.quantum.tests.test_qft.test_RkGate","kind":"function","src_hash":"41056209ce2edf7f","in":{"base":"Any"},"out":{"base":"Any","pred":"RkGate(1, x).k == x and RkGate(1, x).targets == (1,) and RkGate(1, 1) == ZGate(1) and RkGate(2, 2) == PhaseGate(2) and RkGate(3, 3) == TGate(3)"},"spec":{"lhs":"test_RkGate()","rhs":"test_RkGate produces the expected output","over":{"base":"Any"},"name":"test_RkGate_correct"},"guarantee":"test_RkGate produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.physics.quantum.tests.test_qft.test_RkGate_correct","statement":"Path(test_RkGate(x), test_RkGate produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"74ab7aa8b65385f1"}
def test_RkGate():
    x = Symbol('x')
    assert RkGate(1, x).k == x
    assert RkGate(1, x).targets == (1,)
    assert RkGate(1, 1) == ZGate(1)
    assert RkGate(2, 2) == PhaseGate(2)
    assert RkGate(3, 3) == TGate(3)

    assert represent(
        RkGate(0, x), nqubits=1) == Matrix([[1, 0], [0, exp(sign(x)*2*pi*I/(2**abs(x)))]])


