# @cctt_verify {"v":2,"sym":"sympy.physics.quantum.tests.test_qft.test_quantum_fourier","kind":"function","src_hash":"e912d955c02d5ba8","in":{"base":"Any"},"out":{"base":"Any","pred":"QFT(0, 4).decompose()"},"spec":{"lhs":"test_quantum_fourier()","rhs":"test_quantum_fourier produces the expected output","over":{"base":"Any"},"name":"test_quantum_fourier_correct"},"guarantee":"test_quantum_fourier produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.physics.quantum.tests.test_qft.test_quantum_fourier_correct","statement":"Path(test_quantum_fourier(x), test_quantum_fourier produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"3b45fa3ea5220692"}
def test_quantum_fourier():
    assert QFT(0, 3).decompose() == \
        SwapGate(0, 2)*HadamardGate(0)*CGate((0,), PhaseGate(1)) * \
        HadamardGate(1)*CGate((0,), TGate(2))*CGate((1,), PhaseGate(2)) * \
        HadamardGate(2)

    assert IQFT(0, 3).decompose() == \
        HadamardGate(2)*CGate((1,), RkGate(2, -2))*CGate((0,), RkGate(2, -3)) * \
        HadamardGate(1)*CGate((0,), RkGate(1, -2))*HadamardGate(0)*SwapGate(0, 2)

    assert represent(QFT(0, 3), nqubits=3) == \
        Matrix([[exp(2*pi*I/8)**(i*j % 8)/sqrt(8) for i in range(8)] for j in range(8)])

    assert QFT(0, 4).decompose()  # non-trivial decomposition
    assert qapply(QFT(0, 3).decompose()*Qubit(0, 0, 0)).expand() == qapply(
        HadamardGate(0)*HadamardGate(1)*HadamardGate(2)*Qubit(0, 0, 0)
    ).expand()


