# @cctt_verify {"v":2,"sym":"sympy.physics.quantum.tests.test_qft.test_qft_represent","kind":"function","src_hash":"cddeede4941d3176","in":{"base":"Any"},"out":{"base":"Any","pred":"a.evalf(n=10) == b.evalf(n=10)"},"spec":{"lhs":"test_qft_represent()","rhs":"test_qft_represent produces the expected output","over":{"base":"Any"},"name":"test_qft_represent_correct"},"guarantee":"test_qft_represent produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.physics.quantum.tests.test_qft.test_qft_represent_correct","statement":"Path(test_qft_represent(x), test_qft_represent produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"54607092bb05580a"}
def test_qft_represent():
    c = QFT(0, 3)
    a = represent(c, nqubits=3)
    b = represent(c.decompose(), nqubits=3)
    assert a.evalf(n=10) == b.evalf(n=10)
